  const olderToddlerAdvice = [
    { stageKey: 'born_month_18', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 100, title: 'The 18-Month Well-Child Visit', summary: 'The 18-month checkup includes the M-CHAT-R autism second screen, catch-up vaccines, growth review, and a developmental deep dive.', content: 'The 18-month well-child visit is one of the most important toddler checkups. Your pediatrician will administer the M-CHAT-R (autism screen). They will measure weight, length, and head circumference. Vaccines due: Hepatitis A dose #2 and any catch-up doses. Your pediatrician will assess language (10-25+ words expected), motor skills (walking confidently, beginning to run), and social engagement (joint attention, pretend play). Write down your questions beforehand — especially around speech, behavior, and sleep.', source: 'CLINICAL' as ContentSource, tags: ['18 month', 'well child visit', 'M-CHAT-R', 'vaccines'] },
    { stageKey: 'born_month_18', category: 'DEVELOPMENT' as AdviceCategory, priority: 95, title: 'Language Explosion: From 50 to 200+ Words', summary: 'Between 18 and 24 months, vocabulary typically explodes from 50 to 200+ words. Red flags for speech evaluation and how to support language at home.', content: 'Around 18 months, many toddlers enter the "naming explosion" — learning 10-20 new words per week. By 24 months, the average toddler has 200-300 words and begins combining two words ("more milk"). Normal is wide: some 18-month-olds have 10 words, some have 100. Red flags: fewer than 10 words at 18 months, no two-word combinations by 24 months, not following simple commands, regression (losing words). How to support: narrate your day without quizzing, read the same books repeatedly, expand their utterances ("dog" → "Yes, a big brown dog!"), sing songs with gestures.', source: 'DEVELOPMENT' as ContentSource, tags: ['language explosion', 'vocabulary spurt', '18 months', '24 months', 'speech evaluation'] },
    { stageKey: 'born_month_20', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Picky Eating Peaks at 18-24 Months', summary: 'Food neophobia peaks in the second year — evolutionarily normal. The Satter Division of Responsibility and how to survive this phase.', content: 'Picky eating peaks between 18-24 months for biological reasons: growth slows dramatically and food neophobia is evolutionarily adaptive. The Satter Division of Responsibility: parent decides WHAT, WHEN, WHERE. Child decides WHETHER and HOW MUCH. Serve one "safe" food alongside new foods. Do not short-order cook, pressure, or bribe. Expect 15-20 exposures before acceptance — "exposure" includes looking, touching, or mouthing. Trust their internal hunger signals.', source: 'DEVELOPMENT' as ContentSource, tags: ['picky eating', 'food neophobia', 'Satter method', 'toddler nutrition'] },
    { stageKey: 'born_month_20', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'Bedtime Battles and Stall Tactics', summary: '"One more book." "I need water." Toddler stall tactics are legendary. Also: crib climbing and the toddler bed transition.', content: 'Bedtime battles emerge around 18-24 months as your toddler discovers autonomy and stalling. Strategy: build stalls INTO the routine — a "last call" for water, one final book. Use a visual bedtime chart. Offer limited choices ("blue pajamas or red?"). Crib climbing: if your toddler can climb out, transition to a toddler bed or mattress on the floor for safety. Expect boundary testing for 1-2 weeks after any change. Hold the boundary kindly — consistency builds security.', source: 'DEVELOPMENT' as ContentSource, tags: ['bedtime battles', 'stall tactics', 'toddler sleep', 'crib climbing', 'toddler bed'] },
    { stageKey: 'born_month_22', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 85, title: 'Simple Games with Rules', summary: 'Your older toddler can begin to understand simple game rules — hide and seek, simplified Simon Says, matching games.', content: 'Between 18-24 months, your toddler begins to grasp that games have rules — a significant cognitive milestone. Hide and seek: they will "hide" by covering their eyes. Play along — they are practicing theory of mind. Simplified Simon Says: just do action-following — "Touch your nose! Jump!" Matching games: start with 2-3 pairs of identical objects face up. Key principle: the fun is in playing together, not getting rules right. Follow your child\'s lead — they may invent their own version, which is higher-level thinking.', source: 'DEVELOPMENT' as ContentSource, tags: ['games with rules', 'hide and seek', 'Simon Says', 'matching games', 'cognitive development'] },
    { stageKey: 'born_month_22', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 85, title: 'Potty Readiness, Not Potty Training', summary: 'The normal range for potty training spans 18 months to 4+ years. Signs of readiness, why pushing early backfires, and what to focus on instead.', content: 'Potty learning readiness is developmental, not chronological. The normal window spans 18 months to 4+ years — U.S. average is 27-32 months. Readiness signs: stays dry 2+ hours, shows awareness of wet/soiled diaper, can follow two-step instructions, can sit on and get off a potty, shows interest, has words for elimination. What NOT to do: push a child who is not ready — early pressure is associated with withholding, constipation, and longer training timelines. What to do now: get a small potty chair and let it live in the bathroom. Read potty-themed books. Let your child see you use the toilet. Name what is happening. The goal is positive associations — not outcomes.', source: 'DEVELOPMENT' as ContentSource, tags: ['potty training', 'toilet learning', 'readiness signs', 'toddler'] },
  ];
