  const pregnancyAdvice = [
    { stageKey: 'preg_week_4', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 100, title: 'First Trimester: What\'s Happening', summary: 'hCG doubling, dating ultrasound, NIPT and carrier screening, weight gain targets, and what to avoid while the neural tube closes.', content: 'Week 4-5: positive pregnancy test. hCG doubles every 48-72 hours. Week 6-7: dating ultrasound may show heartbeat by 6-7 weeks. Week 10-13: NIPT drawn from 10 weeks — screens for trisomies 21, 18, 13. Carrier screening for CF, SMA, hemoglobinopathies offered. Weight gain: first trimester only 1-4.5 lbs total. Neural tube closes by week 6 — folic acid 400-800 mcg daily critical. Avoid: alcohol, tobacco, raw meat/fish, unpasteurized dairy, high-mercury fish, hot tubs/saunas.', source: 'CLINICAL' as ContentSource, tags: ['first trimester', 'hCG', 'dating ultrasound', 'NIPT', 'folic acid', 'pregnancy'] },
    { stageKey: 'preg_week_8', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 95, title: 'Eating for Two? Actually Not', summary: 'Calorie needs by trimester, the nutrients that matter, and how to manage first-trimester nausea with food strategies.', content: 'Calorie needs: first trimester = no additional calories. Second = +340/day. Third = +450/day. Focus on nutrient density. Critical nutrients: folic acid 400-800 mcg, iron 27 mg, calcium 1000 mg, DHA 200-300 mg, choline 450 mg. Managing nausea: eat small frequent meals — empty stomach worsens nausea. Keep crackers at bedside. Cold foods often better tolerated. Ginger and B6 have evidence. If unable to keep fluids down for 24 hours, call provider — may be hyperemesis gravidarum.', source: 'DEVELOPMENT' as ContentSource, tags: ['pregnancy nutrition', 'calories', 'folic acid', 'iron', 'DHA', 'morning sickness', 'nausea'] },
    { stageKey: 'preg_week_10', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'First Trimester Screening and NIPT', summary: 'NIPT, NT ultrasound, carrier screening, CVS vs. amniocentesis — what each test does and does NOT tell you.', content: 'First trimester screening menu: (1) NIPT — blood draw from 10 weeks, >99% sensitivity for Down syndrome. Screening test, NOT diagnostic. (2) NT ultrasound — 11-13 weeks, measures fluid at back of fetal neck. (3) Carrier screening — one-time blood test for recessive conditions. (4) CVS (10-13 weeks) and amniocentesis (15-20 weeks) are diagnostic with small miscarriage risk (~1 in 500-1,000). You do not have to accept any screening. Both accepting and declining are valid choices.', source: 'CLINICAL' as ContentSource, tags: ['NIPT', 'first trimester screening', 'NT ultrasound', 'carrier screening', 'CVS', 'amniocentesis'] },
    { stageKey: 'preg_week_18', category: 'DEVELOPMENT' as AdviceCategory, priority: 95, title: 'Anatomy Scan: The 20-Week Ultrasound', summary: 'The most detailed ultrasound of pregnancy — what the sonographer checks, when you can learn the sex, and what findings mean.', content: 'The anatomy scan at 18-22 weeks examines every structure: brain, face, spine, heart (four chambers), lungs, diaphragm, stomach, kidneys, bladder, abdominal wall, umbilical cord, placenta location, amniotic fluid. This is when sex can typically be learned. Common benign findings: choroid plexus cysts, echogenic intracardiac focus. Most scans (~95-98%) are reassuring. If a concern is found, you will be referred to maternal-fetal medicine. Go with a full bladder and ask the sonographer to narrate.', source: 'CLINICAL' as ContentSource, tags: ['anatomy scan', '20 week ultrasound', 'fetal development', 'gender reveal'] },
    { stageKey: 'preg_week_20', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Feeling Kicks and Starting to Bond', summary: 'Quickening — first fetal movement — usually 16-22 weeks. Partner bonding tips and why talking to your bump is backed by science.', content: 'Quickening: first-time parents typically feel movement 18-22 weeks. Described as flutters, bubbles, or a goldfish swimming. Anterior placenta may delay feeling kicks to 22-24 weeks — normal. Partners feel kicks from outside around 24-28 weeks. Bonding strategies: talk, sing, read to baby — newborns recognize voices heard in utero. Attend ultrasounds together. Start a journal or voice memos. If you do not feel bonded yet, that is normal too — attachment builds differently for everyone.', source: 'DEVELOPMENT' as ContentSource, tags: ['quickening', 'fetal movement', 'kicks', 'bonding', 'partner bonding', 'second trimester'] },
    { stageKey: 'preg_week_30', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 100, title: 'Third Trimester Monitoring', summary: 'Kick counts, Group B Strep screening, blood pressure checks, and the signs of preeclampsia you must know.', content: 'Third trimester visits increase: every 2 weeks from 28-36 weeks, weekly from 36 weeks. Key monitoring: (1) Kick counts — from 28 weeks, 10 movements in 2 hours. Decrease from normal pattern = call provider immediately. (2) GBS screen — 35-37 weeks, vaginal/rectal swab. 10-30% of pregnant people carry it; IV antibiotics in labor reduce neonatal infection by 80%. (3) Blood pressure — preeclampsia signs: severe headache unresponsive to acetaminophen, vision changes, sudden swelling, RUQ pain. ANY of these = call same day. (4) Growth ultrasound at 32-36 weeks.', source: 'CLINICAL' as ContentSource, tags: ['third trimester', 'kick counts', 'Group B Strep', 'GBS', 'preeclampsia', 'blood pressure'] },
    { stageKey: 'preg_week_36', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Birth Preferences and Hospital Bag', summary: 'Birth preferences — not a rigid plan. What to consider, what to pack, and how to prepare for postpartum.', content: 'Birth preferences are a communication tool, not a contract. Consider: pain management preferences, labor environment, interventions, delivery preferences (delayed cord clamping, skin-to-skin), newborn care (Vitamin K, eye ointment, HepB vaccine — understand before declining). Hospital bag: YOUR going-home outfit (still ~6 months sized), toiletries, long phone charger, snacks. BABY: going-home outfit in two sizes, car seat (installed — non-negotiable). PARTNER: comfortable clothes, snacks, pillow. Postpartum prep at home: freezer meals, peri bottle, maxi pads, stool softeners.', source: 'DEVELOPMENT' as ContentSource, tags: ['birth plan', 'hospital bag', 'postpartum preparation', 'third trimester'] },
    { stageKey: 'preg_week_38', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 100, title: 'Signs of Labor: When to Go to the Hospital', summary: 'Real labor vs. false labor, timing contractions, what water breaking looks like, and exactly when to call your provider.', content: 'Three classic labor signs: (1) REGULAR CONTRACTIONS — time from start to start. 5-1-1 rule: every 5 minutes, lasting 1 minute, for 1 hour. Call provider. Braxton Hicks are irregular and stop with rest/water. (2) WATER BREAKING — often a trickle, not a gush. Call immediately if fluid is green (meconium), you are GBS positive (need antibiotics within 18 hours), or contractions have not started. (3) BLOODY SHOW — blood-tinged mucus, can happen days before labor. If bleeding is bright red and heavy, call immediately. Also call for: decreased fetal movement, severe headache with vision changes, severe abdominal pain that does not relax, or signs of infection. When in doubt, call — that is what the 24-hour line is for.', source: 'CLINICAL' as ContentSource, tags: ['signs of labor', 'contractions', '5-1-1 rule', 'water breaking', 'bloody show', 'when to go to hospital'] },
  ];
