  const gapFillAdviceCards = [
    { stageKey: 'born_week_4', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 95, title: 'Is My Baby Getting Enough Milk?', summary: 'The #1 worry in the first weeks. Wet diaper counts, weight gain patterns, signs of adequate intake, and when to call.', content: 'You cannot measure what goes in, but you can measure what comes out. Wet diapers are your built-in intake meter: 1 on day 1, 2 on day 2, 3 on day 3, 4 on day 4, 6+ per day from day 5 onward. Urine should be pale and odorless. Stools: by day 4-5, expect 3-4 yellow seedy stools per day (breastfed) or 1-2 pasty brown (formula). Weight: normal to lose up to 7-10% of birth weight in first 3-5 days. Should regain by 10-14 days then gain 5-8 oz per week. Signs of adequate intake: alert during wake periods, strong cry, skin bounces back when pinched, soft spot on head is flat (sunken = dehydration). Call doctor if: fewer than 4 wet diapers in 24 hours after day 5, dark brick-dust crystals, lethargy, dry mouth, weight loss beyond 10%. Trust your instincts — if something feels off, call.', source: 'DEVELOPMENT' as ContentSource, tags: ['milk intake', 'wet diapers', 'weight gain', 'dehydration'] },
    { stageKey: 'born_week_6', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Reflux and Spit-Up: Normal vs. GERD', summary: 'Most babies spit up — it is usually normal. How to distinguish physiologic reflux from GERD, management, and when medication is warranted.', content: 'Spitting up affects 50-70% of all infants and peaks around 4-6 months. The cause: immature lower esophageal sphincter. Normal reflux: baby spits up small amounts after feeds, not distressed, gains weight. GERD is different: acid causes inflammation and pain. Red flags: projectile vomiting, green or blood-tinged vomit, refusing to eat, poor weight gain, coughing with feeds. Management: hold upright 20-30 min after feeds, smaller more frequent feeds, burp frequently, avoid tight diapers. Do NOT prop bottles, add cereal to bottles, or elevate crib mattress. If GERD diagnosed, pediatrician may trial hypoallergenic formula or medication. Most babies outgrow reflux by 12-18 months.', source: 'CLINICAL' as ContentSource, tags: ['reflux', 'spit up', 'GERD', 'feeding'] },
    { stageKey: 'born_week_4', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 85, title: 'First Sensory Play: Textures, Sounds, and Mirrors', summary: 'Simple sensory activities for 0-3 months using household items. How your baby\'s senses develop.', content: 'Vision: at birth, baby sees 8-12 inches with high-contrast preference. By 6-8 weeks, tracking across midline. Hearing: recognizes your voice from birth. Touch: the skin is the largest sensory organ. Activities: Texture basket — silk scarf, terry washcloth, velvet ribbon. Stroke gently across palm and cheek. Sound shakers — sealed containers with rice, beans, or a bell. Shake to one side and pause — watch baby\'s eyes drift toward sound. Mirror play — unbreakable mirror during tummy time at eye level. Nature walks — baby-wear and describe what you see, hear, smell. Key: follow baby\'s lead. Overstimulation signs include looking away, hiccupping, yawning. Pause when you see these. Even 3-5 minutes is valuable.', source: 'DEVELOPMENT' as ContentSource, tags: ['sensory play', 'newborn', 'textures', 'mirrors', 'hearing'] },
    { stageKey: 'born_week_6', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 95, title: 'The PURPLE Crying Period', summary: 'Peak crying at 6 weeks is normal and will pass. What PURPLE stands for, how to cope, and the rule you must never break.', content: 'The Period of PURPLE Crying is a normal developmental phase: P-Peak (crying increases weekly, peaking 6-8 weeks), U-Unexpected (starts/stops for no reason), R-Resists soothing, P-Pain-like face, L-Long-lasting (5+ hours/day normal), E-Evening (clusters late afternoon). Begins ~2 weeks, peaks 6-8 weeks, resolves by 3-4 months. Coping: The 5 S\'s (swaddle, side/stomach hold, shush, swing, suck), take shifts with partner, put baby down safely and walk away for 5-10 minutes. Crying has never hurt a baby — but a caregiver at breaking point can. NEVERE shake a baby. Shaking causes brain bleeding, disability, or death in seconds. If you feel the impulse, put baby down and walk away. This phase ends. You are a good parent.', source: 'CLINICAL' as ContentSource, tags: ['PURPLE crying', 'colic', '6 weeks', 'shaken baby syndrome'] },
    { stageKey: 'born_month_4', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'Teething: Timeline, Signs, and Safe Relief', summary: 'First tooth typically 4-7 months. True teething signs, what is NOT caused by teething, safe relief, and what to avoid.', content: 'First tooth — usually lower central incisor — typically 4-7 months. Full set of 20 primary teeth by age 3. True signs: swollen gums, increased drooling, urge to chew, mild irritability, disrupted sleep for 2-3 days before tooth cuts. NOT caused by teething: high fever (>100.4°F), diarrhea, extensive rash. Safe relief: cold refrigerated teething ring, cold wet washcloth, gum massage with clean finger, acetaminophen/ibuprofen (if >6 months) for 1-2 days only. Unsafe: benzocaine gels (FDA black box — methemoglobinemia risk), teething necklaces/bracelets (strangulation), alcohol on gums.', source: 'CLINICAL' as ContentSource, tags: ['teething', 'first tooth', 'safe relief', 'benzocaine'] },
    { stageKey: 'born_month_6', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'First Dental Visit and Fluoride', summary: 'First dentist by age 1 or within 6 months of first tooth. Rice-grain fluoride toothpaste and the no-bottles-in-bed rule.', content: 'AAP and AAPD recommend first dental visit by 12 months or within 6 months of first tooth. Early childhood caries is the most common chronic childhood disease — and preventable. Fluoride: as soon as first tooth appears, brush twice daily with fluoride toothpaste — rice-grain-sized smear under age 3. Non-fluoride "training toothpaste" provides no cavity protection. No bottles in bed with milk or juice — milk pools around teeth all night feeding bacteria. If bedtime bottle necessary, water only. Wean from bottle by 12-15 months. Limit juice to 4 oz/day.', source: 'CLINICAL' as ContentSource, tags: ['first dentist', 'fluoride', 'baby bottle decay', 'oral health'] },
    { stageKey: 'born_month_7', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Baby-Proofing: When and How', summary: 'Once your baby crawls — around 7-9 months — the entire home becomes their environment. A room-by-room checklist.', content: 'Trigger: when baby begins to crawl (7-9 months). Get on hands and knees to see hazards from their perspective. Living room: anchor all furniture to wall with anti-tip brackets. Cover sharp corners. Secure blind cords. Kitchen: cabinet locks on lower cabinets, stove knob covers. Bathroom: never leave standing water, set water heater to 120°F max, toilet locks. Bedroom: crib mattress at lowest setting once pulling to stand. Throughout: outlet covers, baby gates at top AND bottom of stairs, secure cleaning products and medications in high locked cabinet. Post Poison Control: 1-800-222-1222. Goal: a "yes" space where baby explores safely.', source: 'DEVELOPMENT' as ContentSource, tags: ['baby-proofing', 'crawling', 'safety', 'furniture anchoring'] },
    { stageKey: 'born_month_15', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Weaning from Bottle and Pacifier', summary: 'AAP recommends bottle weaning by 12-15 months. How to phase out gently. Dental and speech implications.', content: 'Prolonged bottle use beyond 15 months linked to tooth decay, iron-deficiency anemia, and altered oral-motor development. Bottle weaning: eliminate most optional bottle first, replace with straw cup or open cup, bedtime bottle last to go — shift earlier in routine. Pacifier weaning: cold turkey (most forget in 3-5 days) or gradual restriction (crib only → night only → not at all). After age 3, affects palate shape. Creative: "pacifier fairy" trade-in, snip tip so it loses suction. Expect a few rough days — offer extra comfort and hold the boundary with warmth.', source: 'DEVELOPMENT' as ContentSource, tags: ['bottle weaning', 'pacifier weaning', 'dental health', 'toddler'] },
    { stageKey: 'born_month_15', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Screen Time Guidelines for Under 2s', summary: 'AAP recommends zero screen time before 18 months except video calls. What the research shows.', content: 'AAP: zero screen time before 18 months (exception: live video calls). 18-24 months: high-quality programming with parent co-viewing. Research basis: infants learn through live contingent social interaction — they do NOT learn from screens ("video deficit effect"). Background TV reduces parent-child interaction quality and is associated with language delays. Strategies: no screens in bedroom, turn off when not watching, model healthy habits. Most potent developmental tool: boredom — seed of creativity and independent play. Screens are a tool for you, not enrichment for them.', source: 'CLINICAL' as ContentSource, tags: ['screen time', 'AAP guidelines', 'video deficit', 'toddler'] },
    { stageKey: 'born_month_20', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Toddler Discipline Foundations', summary: 'Redirecting, natural consequences, emotion coaching. The goal is teaching, not punishment.', content: 'Discipline = "to teach." At 18-24 months, prefrontal cortex (self-control) is years from maturity. Core strategies: (1) Redirect — offer acceptable alternative. (2) Natural consequences — throw food, meal ends. (3) Emotion coaching — name the feeling: "You are angry because we left the park." (4) Stay calm — your regulated nervous system co-regulates theirs. (5) Offer two acceptable choices. (6) Pick battles — if safety not at stake, let it go. Avoid: spanking, time-outs longer than 1 min/year, reasoning during tantrum. Most important tool: your relationship — connection before correction.', source: 'DEVELOPMENT' as ContentSource, tags: ['toddler discipline', 'redirecting', 'emotion coaching', 'positive parenting'] },
    { stageKey: 'preg_week_14', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'Pregnancy Sleep Survival Guide', summary: 'Left-side sleeping from T2, pillow configurations, managing insomnia, and safe sleep aids.', content: 'From second trimester (~14 weeks), stop sleeping flat on back — uterus can compress vena cava. Safest: left side-lying. Right side acceptable. Pillow setup: pregnancy pillow (U or C shaped) or DIY — one between knees, one under belly, one behind back, wedge for heartburn. Insomnia: consistent schedule, morning light, no screens 1hr before bed, wind-down ritual. Taper fluids 2hr before bedtime. Safe: Unisom (doxylamine, Category A) and diphenhydramine (Category B). Unsafe: melatonin (under-studied), CBD, alcohol. If severe with racing thoughts, mention at prenatal visit — may be perinatal mood disorder.', source: 'DEVELOPMENT' as ContentSource, tags: ['pregnancy sleep', 'left side sleeping', 'insomnia', 'Unisom'] },
    { stageKey: 'preg_week_24', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 95, title: 'Gestational Diabetes Screening', summary: 'Glucose challenge at 24-28 weeks. What GDM means, how managed, and why screening matters.', content: 'GDM screening at 24-28 weeks. One-hour glucose challenge: drink 50g glucose, blood draw after 1 hour. If elevated, three-hour tolerance test. GDM affects 6-9% of pregnancies. Risks: macrosomia, neonatal hypoglycemia, preterm birth, preeclampsia. Management: diet (carb counting with protein/fat pairing), glucose monitoring, exercise (15-min walk after meals lowers blood sugar). If insufficient: insulin or metformin. Most GDM resolves after delivery — follow-up glucose test at 6-12 weeks postpartum critical. GDM is not your fault — the placenta drives the process. Outcomes are excellent with management.', source: 'CLINICAL' as ContentSource, tags: ['gestational diabetes', 'GDM', 'glucose challenge', 'pregnancy screening'] },
  ];

