  // ─── Born-Month Comprehensive Gap Fill (born_month_7 through born_month_24) ───

  const bornMonthGapFill = [
    { stageKey: 'born_month_7', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 95, title: 'Starting Finger Foods: The Pincer Grasp', summary: 'Around 7-9 months, the pincer grasp emerges. Soft finger foods and self-feeding begin.', content: 'Around 7-8 months, your baby develops the pincer grasp — using thumb and forefinger. Excellent first finger foods: steamed carrot coins, ripe avocado chunks, banana spears, soft pear slices, well-cooked pasta, scrambled egg pieces, soft cheese cubes, shredded chicken. Avoid choking hazards: whole grapes (quarter lengthwise), hot dogs (slice lengthwise), popcorn, whole nuts, hard raw vegetables. Safety: gagging is loud, red-faced, protective — airway clear. Choking is silent, blue-tinged — intervene immediately. Self-feeding builds fine motor skills, autonomy, and a positive food relationship.', source: 'DEVELOPMENT' as ContentSource, tags: ['finger foods', 'pincer grasp', 'self-feeding', 'BLW'] },
    { stageKey: 'born_month_7', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'The 8-Month Sleep Disruption', summary: 'Around 8 months, sleep disruption from two converging cognitive leaps — separation anxiety and object permanence.', content: 'Around 7-9 months, sleep often falls apart for 2-6 weeks. The cause: object permanence — your baby knows you exist when you leave and protests. Combined with separation anxiety (peaking 8-10 months), this creates nighttime wake-ups. Signs: fighting bedtime, standing in crib crying, multiple night wakings. What to do: play separation games during the day (peek-a-boo), practice standing-to-sitting during awake time, do NOT introduce new sleep crutches, keep bedtime routine consistent, brief boring check-ins. This is developmental progression, not regression — it will pass.', source: 'DEVELOPMENT' as ContentSource, tags: ['8 month sleep regression', 'separation anxiety'] },
    { stageKey: 'born_month_9', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Cruising Along Furniture', summary: 'Cruising — walking while holding furniture — typically 8-11 months. Setting up a safe cruising zone.', content: 'Cruising bridges pulling-to-stand to independent walking. Arrange sturdy furniture in a connected circuit — anchor everything to the wall (anti-tip brackets non-negotiable). Barefoot indoors for sensory feedback. Do NOT use seated walkers — associated with delayed motor development and injury risk. Push walkers are safe. Expect falls — your calm response teaches resilience. Red flag: not pulling to stand by 12 months, not cruising by 15 months, or using only one side of the body.', source: 'DEVELOPMENT' as ContentSource, tags: ['cruising', 'furniture cruising', 'gross motor'] },
    { stageKey: 'born_month_9', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Self-Feeding with a Spoon', summary: 'Around 9 months, interest in using a spoon. It will be messy. It is worth it.', content: 'Between 8-10 months, reaching for the spoon is excellent — self-feeding builds motor skills and independence. Use a short thick-handled toddler spoon. Serve "sticky" foods (oatmeal, yogurt, hummus). Pre-load the spoon and hand it handle-first. Have two spoons — one for you, one for them. Embrace the mess — splat mat, bib with catch pocket, strip to diaper. Never pressure or force. Trust hunger and fullness cues. By 12-15 months, many babies use a spoon with moderate success.', source: 'DEVELOPMENT' as ContentSource, tags: ['self-feeding', 'spoon feeding', 'fine motor'] },
    { stageKey: 'born_month_10', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 85, title: 'Peekaboo and Object Permanence Games', summary: 'Peekaboo is not just adorable — it is a cognitive science experiment. Games that build understanding of hidden objects.', content: 'Around 8-10 months, object permanence solidifies. Peekaboo variations: hide behind a blanket or door and peek from different spots, hide a toy under a cloth, use a clear container for "in and out" play, roll a ball behind furniture. Take turns — let baby "hide." Object permanence develops in stages: full visual displacement before invisible displacement (emerges around 12-18 months). These games build the cognitive foundation for separation, memory, and symbolic play.', source: 'DEVELOPMENT' as ContentSource, tags: ['peekaboo', 'object permanence', 'cognitive development'] },
    { stageKey: 'born_month_10', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Babyproofing Audit: Room by Room', summary: 'Once crawling — around 10 months — a serious babyproofing audit. Get on hands and knees and see from their height.', content: 'Living room: anchor ALL furniture to wall studs. Cover sharp corners. Secure blind cords. Mount TVs. Kitchen: magnetic cabinet locks on lower cabinets. Stove knob covers, oven lock. Bathroom: never leave standing water. Set water heater to 120°F max. Toilet locks. Secure all medications. Bedroom: crib mattress at lowest setting. Throughout: outlet covers, baby gates at top AND bottom of stairs. Post Poison Control: 1-800-222-1222. Goal: a "yes" space where baby explores freely.', source: 'DEVELOPMENT' as ContentSource, tags: ['babyproofing', 'safety', 'crawling'] },
    { stageKey: 'born_month_11', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'First Words — What to Expect', summary: 'Around 11-14 months, first meaningful word. What counts, normal range, and how to nurture language.', content: 'First words typically 10-14 months with enormous variation. What counts: any consistent sound used meaningfully — animal sounds, signs, word approximations. The average 12-month-old has 1-3 words beyond "mama" and "dada." Receptive language far outpaces expressive — your baby understands 50-100+ words. How to support: narrate without quizzing, read the same books repeatedly, expand utterances ("dog" → "Yes, a big brown dog!"), sing songs with gestures, respond to all communication attempts. Red flags: no babbling by 9 months, no meaningful words by 15 months, loss of previously acquired language.', source: 'DEVELOPMENT' as ContentSource, tags: ['first words', 'language development', 'speech'] },
    { stageKey: 'born_month_11', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'Weaning from Bottle: The Timeline', summary: 'AAP recommends weaning from the bottle by 12-15 months. Why it matters and a gentle plan.', content: 'Prolonged bottle use beyond 15 months linked to tooth decay, iron-deficiency anemia, and altered oral-motor development. Weaning plan: start by 11-12 months. Eliminate the most optional bottle first. Replace with straw cup or open cup. Morning and bedtime bottles are usually last — shift bedtime bottle earlier in routine. Transition to whole milk at 12 months — limit to 16-24 oz/day. NEVER put baby to bed with a bottle — #1 cause of bottle rot. Expect resistance — the bottle is comfort. Offer extra cuddles and stay consistent.', source: 'CLINICAL' as ContentSource, tags: ['bottle weaning', 'dental health', 'iron deficiency'] },
    { stageKey: 'born_month_13', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Walking Independently: The Wide Normal Range', summary: 'Walking has the widest normal range of any motor milestone — 9 to 18 months. Progression matters more than date.', content: 'Typical progression: pulling to stand (8-10 months), cruising (9-12 months), standing without support (10-13 months), first independent steps (11-15 months), walking confidently (12-18 months). Support: push toys (NOT seated walkers), barefoot indoors, arrange furniture for cruising, kneel a few feet away with outstretched arms. Do NOT "walk" them by holding hands above their head — this puts center of gravity wrong and can cause nursemaid\'s elbow. Red flags: not pulling to stand by 12 months, not walking by 18 months, persistent toe-walking, asymmetry.', source: 'DEVELOPMENT' as ContentSource, tags: ['walking', 'first steps', 'gross motor'] },
    { stageKey: 'born_month_13', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Transitioning Off Formula Completely', summary: 'At 12 months, formula is no longer necessary. Transition to whole milk and predominantly solid foods.', content: 'At 12 months, switch to whole milk (3.25% fat) — toddlers need fat for brain myelination. No reduced-fat milk before age 2. Limit milk to 16-24 oz/day total dairy — more crowds out iron-rich solids. Transition gradually: mix formula/milk 75/25 → 50/50 → 25/75 → 100%. Serve in a straw cup or open cup. If refusing milk: try warming, serving with meals, or offering dairy in other forms. Plant-based milks (almond, oat) are NOT nutritionally equivalent — fortified soy milk is closest. Breastfeeding past 12 months is wonderful — continue as long as it works for both of you.', source: 'DEVELOPMENT' as ContentSource, tags: ['formula transition', 'whole milk', 'toddler nutrition'] },
    { stageKey: 'born_month_14', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'Separation Anxiety at Bedtime', summary: 'Separation anxiety often resurges 14-18 months as toddlers understand they are separate beings.', content: 'This is developmentally normal. Bedtime strategies: build connection INTO the routine — 10-15 minutes of focused one-on-one play before starting bedtime. Introduce a transitional object (lovey) — safe after 12 months. Create a brief boring check-in protocol: 1-2 minutes in the dark, same phrase each time. Never sneak away — this breaks trust. Practice short daytime separations. Consider a toddler clock (OK-to-wake light). Red flag: if severe enough to interfere with daily functioning or no improvement after 4-6 weeks of consistent response.', source: 'DEVELOPMENT' as ContentSource, tags: ['separation anxiety', 'bedtime', 'toddler sleep'] },
    { stageKey: 'born_month_14', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 85, title: 'Sensory Bins and Texture Play', summary: 'Sensory bins engage multiple senses, building neural connections and fine motor skills.', content: 'For 12-18 months: shallow plastic bin with taste-safe base (dry rice, dry beans, oatmeal). Add scoops, measuring cups, small bowls, large pom-poms. Supervision mandatory. Ideas: rainbow rice (dye with vinegar and food coloring), water play on a towel, nature bin (pinecones, large stones, leaves), whipped cream "paint" on high chair tray, Jello dig with safe toys. Rotate materials every 1-2 weeks. Expect mess — lay down a shower curtain. The sensory table remains beloved through preschool.', source: 'DEVELOPMENT' as ContentSource, tags: ['sensory bins', 'texture play', 'toddler activities'] },
    { stageKey: 'born_month_16', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Building a 10-Word Vocabulary', summary: 'Between 15-18 months, most toddlers have 10-25 meaningful words. How vocabulary builds.', content: 'At 15-18 months, typical vocabulary ranges 10-50+ words with enormous variation. What counts: word approximations, animal sounds, signs, exclamations. Receptive vocabulary is 5-10 times larger than expressive. Around 18 months, many enter the "naming explosion." How to support: expand without correcting, offer choices, read the same books repeatedly, narrate throughout the day, listen and wait — count to 5-10 after asking a question. Red flags: fewer than 3-5 words at 15 months, fewer than 10 at 18 months, not following simple commands, loss of previously used words.', source: 'DEVELOPMENT' as ContentSource, tags: ['vocabulary', 'language development', 'speech delay'] },
    { stageKey: 'born_month_16', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Discipline vs. Redirection', summary: 'Your toddler\'s prefrontal cortex is years from maturity. A practical guidance framework.', content: 'At 15-18 months, the limbic system (emotion, impulse) is fully online but the prefrontal cortex (self-control) won\'t mature until the mid-20s. What works: redirection, environment control, natural consequences, emotion coaching, offering two choices, picking battles, connection before correction. What to avoid: spanking, time-outs longer than 1 minute per year, reasoning during a tantrum (thinking brain offline), shaming. The goal is teaching, not punishment. You are building a long-term relationship, not winning a short-term battle.', source: 'DEVELOPMENT' as ContentSource, tags: ['toddler discipline', 'positive parenting'] },
    { stageKey: 'born_month_17', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Managing Picky Eating: The Peak Phase', summary: 'Picky eating peaks 12-24 months for evolutionary reasons. Evidence-based strategies.', content: 'Food neophobia peaks 12-24 months — evolutionarily adaptive as toddlers become mobile. The Satter Division of Responsibility: parent decides WHAT, WHEN, WHERE; child decides WHETHER and HOW MUCH. Practical: serve one safe food alongside new foods, family meals, expect 15-20 exposures before acceptance, do NOT short-order cook, do NOT pressure or bribe, serve dessert with the meal occasionally. Trust their hunger and fullness signals — some days everything, some days three crackers. Red flag: consistent weight loss, crossing two major growth percentile lines downward.', source: 'DEVELOPMENT' as ContentSource, tags: ['picky eating', 'Satter method', 'toddler nutrition'] },
    { stageKey: 'born_month_17', category: 'DEVELOPMENT' as AdviceCategory, priority: 85, title: 'Stacking and Sorting Milestones', summary: 'Between 15-18 months — stacking blocks, simple shape sorting, beginning problem-solving.', content: 'Typical progression: stacks 2 blocks (12-15 months), stacks 3-4 blocks (16-18 months), stacks 5-6 blocks (20-22 months). Simple shape sorting: circle first (no corners to orient) around 15-18 months. Square and triangle follow months later. Support with 1-inch wooden cubes, demonstrate building and knocking down. For shape sorting: tape over all holes except circle, add one shape at a time. Do not correct or take over — learning is in the attempt. These build hand-eye coordination, spatial reasoning, and persistence — foundations for later math and writing.', source: 'DEVELOPMENT' as ContentSource, tags: ['stacking blocks', 'shape sorting', 'fine motor'] },
    { stageKey: 'born_month_19', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 95, title: '18-Month Well-Child Checkup', summary: 'The 18-month visit — M-CHAT-R autism screening, catch-up vaccines, growth and developmental assessment.', content: 'What to expect: (1) Growth — weight, length, head circumference on WHO charts. (2) M-CHAT-R — 20-question autism screening. Answer honestly — positive screen means further evaluation needed, not a diagnosis. (3) Vaccines — Hepatitis A #2, catch-up doses, flu/COVID if seasonal. (4) Anemia and lead screening if not done at 12 months. (5) Assessment: walking/running, vocabulary (10-25+ words), social engagement, feeding, behavior. (6) Anticipatory guidance: toilet learning readiness, sleep, dental health, screen time, safety (car seat rear-facing until at least age 2). Write questions beforehand.', source: 'CLINICAL' as ContentSource, tags: ['18 month checkup', 'M-CHAT-R', 'autism screening'] },
    { stageKey: 'born_month_19', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Two-Word Phrases Emerging', summary: 'Between 18-24 months, combining two words — a major language milestone.', content: 'Two-word combinations typically 18-24 months. Early types: agent+action ("daddy go"), action+object ("eat cookie"), possessor+possession ("my shoe"), entity+location ("baby chair"), negation ("no bed"). Early sentences are telegraphic — omitting grammar markers. Expand by one element: "daddy go" → "Yes, Daddy went to work!" Do NOT demand imitation — turns communication into performance. Model correct grammar naturally. Read books with repetitive phrases. Create communication temptation (toy in clear container they cannot open). Red flag: no two-word combinations by 24 months.', source: 'DEVELOPMENT' as ContentSource, tags: ['two word phrases', 'telegraphic speech', 'language'] },
    { stageKey: 'born_month_21', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'Night Terrors vs. Nightmares', summary: 'Completely different phenomena — knowing the difference changes how you respond.', content: 'Nightmares: REM sleep, second half of night, child wakes fully and seeks comfort, can recall dream. Respond with comfort and reassurance. Night terrors: non-REM deep sleep, first 1-3 hours after bedtime, child appears awake but is NOT — screaming, thrashing, glassy stare, inconsolable, NO memory. CRITICAL: Do NOT try to wake — this prolongs and intensifies the episode. Ensure safety and wait 5-20 minutes. Not psychological disturbance — a parasomnia triggered by overtiredness or schedule disruption. Most outgrow by early childhood.', source: 'DEVELOPMENT' as ContentSource, tags: ['night terrors', 'nightmares', 'sleep parasomnia'] },
    { stageKey: 'born_month_21', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 85, title: 'Parallel Play and Early Social Skills', summary: 'Parallel play — playing alongside rather than with — is the dominant form from 18-30 months.', content: 'Stages: solitary (0-18m), parallel (18-30m — playing near others with similar materials, aware but not interacting), associative (2.5-3.5y — interacting loosely without shared goal), cooperative (3.5+y — true shared play). Support: provide duplicates of popular toys, keep playdates short (45-60 min) and small, supervise but do not direct, model social language. Sharing is not developmentally expected at this age. Red flag: no interest in other children at all, extreme withdrawal, or persistent aggression unresponsive to redirection.', source: 'DEVELOPMENT' as ContentSource, tags: ['parallel play', 'social development', 'play stages'] },
    { stageKey: 'born_month_23', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Portion Sizes for Toddlers', summary: 'A toddler\'s stomach is the size of their fist. Realistic portions and trusting appetite.', content: 'A 2-year-old\'s stomach capacity is approximately their clenched fist. Typical meal: 2 Tbsp protein, 2 Tbsp grain, 2 Tbsp vegetables, 2 Tbsp fruit. Appetite fluctuates dramatically day to day — look at intake over a WEEK, not a day. Serve small portions initially — large plates overwhelm. One safe food per meal. Milk limit 16-24 oz/day — more crowds out solids. Make every bite count: nutrient density over volume. Your job: provide food at predictable times. Their job: decide whether and how much. When you trust this division, mealtime tension dissolves.', source: 'DEVELOPMENT' as ContentSource, tags: ['portion sizes', 'toddler nutrition', 'hunger cues'] },
    { stageKey: 'born_month_23', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Preparing for the 2-Year Milestones', summary: 'The 2-year mark brings a developmental leap in language, motor, social, and independence.', content: 'Around 24 months: language explosion (50→200+ words, simple sentences), motor (running, kicking, beginning to jump), independence surge ("I do it myself!"), expanded pretend play, big emotions (with more language comes more frustration), growing interest in other children. Prepare: childproof for safe exploration, offer choices to channel independence, consistent routines for security, read books about feelings daily, schedule the 2-year checkup, consider toddler bed if climbing out of crib. Remember: the behaviors that challenge you most are signs of healthy development.', source: 'DEVELOPMENT' as ContentSource, tags: ['2 year milestones', 'developmental leap', 'independence'] },
    { stageKey: 'born_month_24', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 95, title: '2-Year Checkup and Developmental Screening', summary: 'Comprehensive 2-year visit — second M-CHAT-R, vaccine review, lead and anemia re-screen.', content: 'What to expect: (1) Growth — BMI now calculated. (2) M-CHAT-R — second routine autism screen at 24 months increases detection. (3) Developmental assessment — language (50-200+ words, two-word combinations), motor (running, kicking, stairs, jumping), cognitive (pretend play, following two-step commands), social-emotional (independence, interest in other children). (4) Lead screening — universal at 12 and 24 months. (5) Hemoglobin/anemia. (6) Anticipatory guidance: toilet learning readiness (U.S. average 27-32 months), crib-to-bed transition, managing tantrums, dental visit, screen time, car seat (remain rear-facing until maxing out seat limits). Write down your questions — you know your child best.', source: 'CLINICAL' as ContentSource, tags: ['2 year checkup', 'lead screening', 'toilet learning'] },
    { stageKey: 'born_month_24', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'From Baby to Toddler — Your Emotional Journey', summary: 'The second birthday marks a transition. Permission to feel everything.', content: 'The second birthday can bring mixed emotions: pride, grief for the baby they were, relief that the intense infant stage is behind you, anxiety about what comes next. All valid. What you might feel: nostalgia packing away baby clothes, exhaustion from new toddler challenges, joy watching new skills, identity shifts, relationship changes. What helps: mark the transition meaningfully, connect with other toddler parents, reflect on how far you have come, write a letter to yourself two years ago. If sadness or anxiety persists, perinatal mood disorders can onset anytime in the first three years. Talk to your provider. Celebrate: your baby is healthy, growing, and becoming their own person. That is your success.', source: 'DEVELOPMENT' as ContentSource, tags: ['toddler transition', 'parent well-being', 'emotional journey'] },
  ];

