  const newMilestones = [
    { stageKey: 'born_week_1', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Lifts Head Briefly During Tummy Time', description: 'Your newborn can briefly lift their head and turn it to the other side during supervised tummy time. Head control is the foundation for all future motor development.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Place baby chest-to-chest on your reclined body for 2-3 minutes, 2-3 times per day. Get face-to-face and talk softly. This counts as tummy time and builds neck strength.', xpReward: 10 },
    { stageKey: 'born_week_1', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Recognizes Parent\'s Voice and Scent', description: 'Your newborn can distinguish your voice and scent from others, turning their head toward you and showing calming responses. This recognition began in the womb and deepens through daily interaction.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Hold your baby close and talk softly. Partners: spend skin-to-skin time so your baby learns your unique voice and smell too.', xpReward: 10 },
    { stageKey: 'born_week_4', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Hands Beginning to Open', description: 'Your newborn\'s hands are starting to spend more time open rather than tightly fisted. The palmar grasp reflex is gradually relaxing.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Gently stroke the back of your baby\'s hand to encourage opening. Offer a soft cloth or your clean finger for them to grasp and release.', xpReward: 10 },
    { stageKey: 'born_week_4', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Cooing and Gurgling Sounds', description: 'Your baby begins making soft vowel-like cooing and gurgling sounds beyond crying — the earliest vocal experiments and foundation of language.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'When your baby coos, respond with exaggerated facial expressions and talk back. Leave pauses for them to "answer." This back-and-forth is the earliest conversation.', xpReward: 15 },
    { stageKey: 'born_week_4', domain: 'COGNITIVE' as MilestoneDomain, title: 'Tracks Objects Across Midline', description: 'Your baby can follow a slowly moving object or face with their eyes as it crosses from one side to the other — a key neurological milestone.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Hold a high-contrast card 8-12 inches from your baby\'s face. Move it slowly from side to side. Celebrate any tracking, even brief!', xpReward: 15 },
    { stageKey: 'born_week_6', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'First Social Smile', description: 'Your baby gives their first genuine social smile in response to your face and voice — not reflexive sleep smiles, but a true responsive connection.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Get close (8-12 inches), smile warmly, and talk in a sing-song voice. Wait — the smile may take a few seconds. Celebrate this moment!', xpReward: 25 },
    { stageKey: 'born_week_6', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Holds Head at 45 Degrees in Tummy Time', description: 'During tummy time, your baby lifts their head to approximately 45 degrees and holds it for several seconds.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Get down on the floor face-to-face during tummy time. Place a mirror at their eye level. Aim for 15-20 minutes total tummy time per day.', xpReward: 15 },
    { stageKey: 'born_week_8', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Vocal Play — Squealing and Laughing', description: 'Your baby expands beyond cooing to include delighted squealing, laughing, and experimenting with different sounds.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Try gentle silliness: blow raspberries, make funny animal sounds, or play peek-a-boo. Respond enthusiastically to their vocal play.', xpReward: 15 },
    { stageKey: 'born_week_8', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Brings Hands to Mouth', description: 'Your baby deliberately brings their hands to their mouth for exploration and self-soothing. Mouthing is a primary way babies learn about objects.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Ensure hands are clean and nails trimmed. Offer a soft teething ring for oral exploration. This is an important self-regulation skill.', xpReward: 10 },
    { stageKey: 'born_month_1', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Head Control Improving — Lifts to 90 Degrees', description: 'Your baby can now lift their head to approximately 90 degrees during tummy time and hold it steady while looking around.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Continue daily tummy time — aim for 20-30 minutes total. Introduce a nursing pillow under the chest for support. Move toys in a semi-circle to encourage head turning.', xpReward: 15 },
    { stageKey: 'born_month_1', domain: 'COGNITIVE' as MilestoneDomain, title: 'Recognizes Familiar Faces at a Distance', description: 'Your baby recognizes familiar faces from several feet away and may show preference with brightened eyes, quieting, or smiling.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'When you enter the room, pause and say hello before picking up your baby. Encourage other familiar caregivers to do the same.', xpReward: 15 },
    { stageKey: 'born_month_1', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Calms When Spoken To', description: 'Your baby visibly calms — slowing breathing, relaxing muscles — when you speak in a gentle voice. Your voice is a powerful regulatory tool.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'When your baby is fussy, hold them close and speak in a low, rhythmic voice. Your calm presence co-regulates their nervous system.', xpReward: 15 },
    { stageKey: 'born_month_2', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Grasps and Shakes Hand Toys', description: 'Your baby deliberately grasps a rattle or small toy placed in their hand and shakes it with purpose, exploring cause and effect.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Offer lightweight, easy-grasp rattles. Place them in your baby\'s hand and gently help them shake. Vary the toys — different sounds and textures.', xpReward: 10 },
    { stageKey: 'born_month_2', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Vowel Sounds — \'Ooh\' and \'Aah\'', description: 'Your baby produces clear, resonant vowel sounds with varied pitch and volume, taking conversational turns — the earliest form of dialogue.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Have "conversations": when they vocalize, respond with an animated face, then pause 5-10 seconds — your baby may take a turn.', xpReward: 15 },
    { stageKey: 'born_month_2', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Pushes Up on Forearms During Tummy Time', description: 'Your baby pushes up on their forearms with elbows under shoulders, lifting their chest off the floor — a major strength milestone.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Place a rolled towel under the chest for support. Lie face-to-face on the floor. Place toys slightly elevated to encourage pushing higher.', xpReward: 15 },
    { stageKey: 'born_month_4', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Rolls from Tummy to Back', description: 'Your baby can roll from their stomach to their back, usually starting accidentally during tummy time and becoming intentional.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Place a favorite toy to one side just out of reach. Gently rock your baby\'s hips side to side to model the motion. Celebrate every roll!', xpReward: 20 },
    { stageKey: 'born_month_4', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Reaches for and Grabs Objects', description: 'Your baby deliberately reaches with one or both hands, successfully grasps an object, and brings it to their mouth for exploration.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Offer lightweight toys at chest level during back play. Present toys slightly to one side to encourage reaching across the body\'s midline.', xpReward: 15 },
    { stageKey: 'born_month_4', domain: 'COGNITIVE' as MilestoneDomain, title: 'Explores Objects with Mouth and Hands', description: 'Your baby uses both hands and mouth to explore objects — shaking, banging, mouthing. Multi-sensory exploration is how babies understand the world.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Provide safe, clean objects with different textures: silicone spatula, wooden ring, crinkly fabric. Rotate objects to maintain novelty.', xpReward: 15 },
    { stageKey: 'born_month_5', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Responds to Own Name', description: 'Your baby consistently turns their head or pauses when they hear their own name, distinguishing it from other words.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Use your baby\'s name frequently in positive contexts. Play name games — call from different spots and celebrate when they turn.', xpReward: 15 },
    { stageKey: 'born_month_5', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Raspberries and Babbling', description: 'Your baby blows raspberries and produces repetitive consonant-vowel combinations like "ba-ba" — the direct precursor to speech.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Imitate your baby\'s sounds — echo their babbles. Turn-taking in babbling games builds conversational rhythm. Face your baby so they watch your mouth.', xpReward: 15 },
    { stageKey: 'born_month_5', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Sits with Support', description: 'Your baby can sit upright with support — propped with pillows or in a supportive seat — with good head and trunk control.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Use a nursing pillow for supported floor sitting. Sit behind your baby and gently reduce support as trunk control strengthens.', xpReward: 15 },
    { stageKey: 'born_month_6', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Transfers Objects Between Hands', description: 'Your baby passes a toy from one hand to the other, coordinating both sides of the body across the midline — a sign of brain integration.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Hand your baby a toy in one hand, then offer a second toy on that same side — they must transfer to grasp the new one.', xpReward: 15 },
    { stageKey: 'born_month_6', domain: 'COGNITIVE' as MilestoneDomain, title: 'Looks for Dropped Objects', description: 'Your baby looks down to find a toy they have dropped, demonstrating emerging object permanence — understanding objects exist when unseen.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Deliberately drop a toy where your baby can see it land. Pause — do their eyes track to the floor? Pick it up with excitement!', xpReward: 15 },
    { stageKey: 'born_month_7', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Sits Without Support', description: 'Your baby sits on the floor with a straight back, hands free for play, no external support needed. This frees both hands for exploration.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Place a nursing pillow behind as a crash pad. Sit face-to-face and offer toys at chest level. Celebrate this new view!', xpReward: 25 },
    { stageKey: 'born_month_7', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Babbles with Consonants — \'Ba-ba, Da-da\'', description: 'Your baby produces clear, repeated consonant-vowel combinations. This canonical babbling is the direct precursor to first words.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Echo your baby\'s babbles enthusiastically. Add a new sound and pause — they may imitate. Narrate your day in simple language.', xpReward: 20 },
    { stageKey: 'born_month_7', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Engages in Social Games', description: 'Your baby actively participates in simple social games like peek-a-boo and pat-a-cake, anticipating the next step.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Play peek-a-boo with variation — hide behind a blanket, door, your hands. Take turns — let your baby initiate sometimes.', xpReward: 15 },
    { stageKey: 'born_month_8', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Army Crawling or Scooting', description: 'Your baby moves across the floor by pulling with arms — army crawling, creeping, or scooting. Any independent forward locomotion counts.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Create a large safe floor space. Place irresistible toys just out of reach. Get on the floor and crawl alongside — your baby will mimic.', xpReward: 25 },
    { stageKey: 'born_month_8', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Pincer Grasp Emerging', description: 'Your baby begins using the pads of thumb and index finger to pick up small objects — the early pincer grasp unlocking self-feeding.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Scatter safe finger foods on the high-chair tray. Model picking up pieces with your own pincer grasp. Provide a container with safe small objects.', xpReward: 20 },
    { stageKey: 'born_month_8', domain: 'COGNITIVE' as MilestoneDomain, title: 'Understands Object Permanence', description: 'Your baby searches for a hidden object — lifting a cloth to find a toy underneath. Object permanence has solidified.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Hide a favorite toy partially under a cloth and ask "Where did it go?" Gradually progress to fully hidden. Play "in and out" games.', xpReward: 25 },
    { stageKey: 'born_month_9', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Responds to Simple Verbal Requests', description: 'Your baby responds to simple verbal cues like "come here" or "wave bye-bye" — with or without gestures. Understanding far outpaces speaking.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Use consistent simple phrases paired with gestures. Celebrate every response — even partial. Avoid quizzing; just model language naturally.', xpReward: 20 },
    { stageKey: 'born_month_9', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Pulls to Stand', description: 'Your baby grasps furniture and pulls themselves from sitting to standing — requiring coordinated whole-body strength.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Lower crib mattress to lowest setting NOW. Anchor all furniture to wall. Practice sitting back down — many babies get "stuck" standing.', xpReward: 25 },
    { stageKey: 'born_month_10', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Pincer Grasp Refined — Picks Up Small Objects', description: 'Precise thumb-and-forefinger grip with accuracy. This unlocks independent self-feeding, pointing, and detailed exploration.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Scatter safe finger foods on the tray. Practice with non-food items: large pom-poms, chunky wood pieces. Supervise closely.', xpReward: 20 },
    { stageKey: 'born_month_10', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Waves Bye-Bye', description: 'Your baby waves in response to someone leaving — one of the earliest conventional gestures. Gestures are a critical bridge to spoken language.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Wave bye-bye consistently when leaving. Take your baby\'s hand and gently help them wave. Celebrate any attempt — gestures count as communication.', xpReward: 15 },
    { stageKey: 'born_month_11', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Stands Alone Briefly', description: 'Your baby lets go of furniture and stands independently for a few seconds — the final motor step before first independent steps.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Offer a captivating toy while baby stands at a low surface — they may let go to hold it. Celebrate every second of independent standing.', xpReward: 25 },
    { stageKey: 'born_month_11', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Says First Meaningful Word', description: 'Your baby uses a consistent sound with clear intent beyond "mama" and "dada." A meaningful word is used intentionally in the right context.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'When your baby vocalizes, respond as if they said something meaningful. Expand: "Ba!" → "Yes, that\'s a ball!" Animal sounds count as words.', xpReward: 30 },
    { stageKey: 'born_month_12', domain: 'COGNITIVE' as MilestoneDomain, title: 'Follows Simple One-Step Commands', description: 'Your baby follows simple verbal commands without visual cues — "Give me the ball." Receptive language is well established.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Give simple one-step directions during daily routines. Use a warm tone. Celebrate the attempt — partial completion counts.', xpReward: 20 },
    { stageKey: 'born_month_12', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Puts Objects Into Container', description: 'Your baby deliberately places objects into a container and dumps them out repeatedly — learning containment, volume, and cause and effect.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Provide a basket with safe objects of different sizes. Model putting one in and dumping out. Let them repeat as long as they want.', xpReward: 20 },
    { stageKey: 'born_month_12', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Imitates Adult Actions', description: 'Your toddler watches you and deliberately copies everyday actions — talking on a toy phone, stirring with a spoon. Imitation is the primary learning mechanism.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Provide simple props: toy phone, wooden spoon and bowl. Perform the action slowly, hand the prop over, and wait. Do not instruct — let them discover.', xpReward: 20 },
    { stageKey: 'born_month_14', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Walks Independently — Confident Steps', description: 'Your toddler walks across the room independently with a wide-based waddling gait — arms held high for balance. Walking is now their primary mobility.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Provide open safe floor space. Push toys build confidence. Barefoot indoors. Kneel a few feet away and encourage them to walk to you.', xpReward: 25 },
    { stageKey: 'born_month_14', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Vocabulary of 3-5 Words', description: 'Your toddler consistently uses 3-5 words with meaning. Animal sounds, word approximations, and signs all count. Receptive vocabulary far exceeds expressive.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Expand on their words. Narrate without quizzing. Read the same books repeatedly. Listen and wait — count to 10 after asking a question.', xpReward: 20 },
    { stageKey: 'born_month_16', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Scribbles with Crayon', description: 'Your toddler picks up a crayon and makes marks on paper — using a fisted grip and whole-arm movement. The very beginning of writing.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Tape large paper securely to table or floor. Offer chunky washable crayons. Sit alongside and scribble too — do not direct or teach grip.', xpReward: 15 },
    { stageKey: 'born_month_16', domain: 'COGNITIVE' as MilestoneDomain, title: 'Points to 1-2 Body Parts', description: 'When asked "Where is your nose?" your toddler points to or touches 1-2 body parts — emerging body awareness and receptive vocabulary.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Sing "Head, Shoulders, Knees and Toes" with actions. Point to your own nose, then theirs. Start with 1-2 parts and add gradually.', xpReward: 15 },
    { stageKey: 'born_month_18', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Runs — Awkward but Enthusiastic', description: 'Your toddler runs with a flat-footed wide-based gait, arms held high — enthusiastic and unsteady. True running with a flight phase is still emerging.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Play chase games in a safe open space. Let them chase you more than you chase them. Accept the tumbles — your calm response teaches resilience.', xpReward: 20 },
    { stageKey: 'born_month_18', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: '10-25 Word Vocabulary', description: 'Your toddler consistently uses 10-25 meaningful words, with new words appearing every few days. Many enter the "naming explosion" around 18 months.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Expand their utterances. Read favorite books repeatedly. Do not correct pronunciation directly — model the word correctly in your response.', xpReward: 25 },
    { stageKey: 'born_month_18', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Shows Affection Spontaneously', description: 'Your toddler initiates hugs, kisses, pats, or cuddles without prompting — genuine displays of affection demonstrating secure attachment.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Accept affection warmly when offered, but never force it. Model affection with your partner. Name the feeling: "That hug feels like love!"', xpReward: 20 },
    { stageKey: 'born_month_20', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Stacks 4-6 Blocks', description: 'Your toddler deliberately stacks 4-6 blocks, carefully placing each one — requiring refined hand-eye coordination and controlled release.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Use 1-inch wooden cubes. Build together — you place one, they place one. Knock towers down dramatically. Do not build "for" them.', xpReward: 20 },
    { stageKey: 'born_month_20', domain: 'COGNITIVE' as MilestoneDomain, title: 'Engages in Simple Pretend Play', description: 'Your toddler uses objects symbolically — feeding a doll, holding a block like a phone. Symbolic thinking is a landmark cognitive achievement.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Provide simple props: doll, toy phone, wooden spoon and bowl. Model once, hand over, step back. Join in when invited but let them lead.', xpReward: 25 },
    { stageKey: 'born_month_22', domain: 'LANGUAGE_COMMUNICATION' as MilestoneDomain, title: 'Two-Word Phrases Emerging', description: 'Your toddler combines two words: "more milk," "daddy go." Telegraphic speech — omitting grammar markers — is the normal first stage of sentences.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Expand by one element: "more milk" → "You want more milk!" Model correct grammar without correcting directly. Create communication temptation.', xpReward: 30 },
    { stageKey: 'born_month_22', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Parallel Play Alongside Peers', description: 'Your toddler plays near other children with similar materials — aware of peers but not yet interacting. Parallel play is dominant from 18-30 months.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Arrange short playdates with 1-2 other toddlers. Provide duplicate toys. Supervise but do not direct. Sharing is not developmentally expected.', xpReward: 20 },
    { stageKey: 'born_month_24', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Jumps with Both Feet Leaving Ground', description: 'Your toddler jumps up and both feet clear the floor simultaneously — a significant bilateral coordination achievement requiring strength and courage.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Model jumping — make it silly. Hold both their hands and jump together. Practice on soft surfaces. Some toddlers jump first off a low step.', xpReward: 25 },
    { stageKey: 'born_month_24', domain: 'COGNITIVE' as MilestoneDomain, title: 'Completes Simple Puzzles (3-4 pieces)', description: 'Your toddler completes a simple wooden puzzle with 3-4 pieces — involving visual-spatial reasoning, shape discrimination, and persistence.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Start with single-piece puzzles. Tape over unused holes. Demonstrate slowly, then let them try. The struggle is the learning.', xpReward: 20 },
    { stageKey: 'born_month_24', domain: 'FINE_MOTOR' as MilestoneDomain, title: 'Turns Pages One at a Time', description: 'Your toddler turns board book pages one at a time rather than grabbing handfuls — refined finger control enabling independent book exploration.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Read board books daily. Slide your finger under the next page to create a gap. Let them control the pace — the goal is joyful engagement.', xpReward: 15 },
    { stageKey: 'preg_week_5', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Neural Tube Closes', description: 'The neural tube — which will become your baby\'s brain and spinal cord — completes closure by day 28. Folic acid is critical during this window.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'This milestone often occurs before you know you are pregnant. Ensure 400-800 mcg folic acid daily if in conception window.', xpReward: 20 },
    { stageKey: 'preg_week_14', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Placenta Fully Functional', description: 'By week 14, the placenta has fully taken over hormone production and nutrient exchange — often bringing relief from first-trimester symptoms.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Many parents notice renewed energy. This marks the true beginning of the second trimester. Your baby is now about the size of a lemon.', xpReward: 20 },
    { stageKey: 'preg_week_22', domain: 'COGNITIVE' as MilestoneDomain, title: 'Baby Responds to Touch on Belly', description: 'Your baby may respond to external touch on your belly with movement — their sensory nervous system is developing rapidly.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Gently press on your belly and see if baby responds. Partners can try this too — a wonderful way to begin connecting.', xpReward: 20 },
    { stageKey: 'preg_week_34', domain: 'GROSS_MOTOR' as MilestoneDomain, title: 'Baby\'s Immune System Developing', description: 'Your baby\'s immune system matures rapidly, receiving passive antibodies from you through the placenta — protection lasting months after birth.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Ensure Tdap (27-36 weeks), flu shot, and COVID vaccine — these transfer protective antibodies. Baby gains about half a pound per week.', xpReward: 25 },
    { stageKey: 'preg_week_38', domain: 'SOCIAL_EMOTIONAL' as MilestoneDomain, title: 'Baby Ready for Bonding Outside the Womb', description: 'At 38 weeks, your baby is fully developed and ready for life outside — and for the profound bonding that begins at birth.', status: 'EXPECTED' as MilestoneStatus, activityPrompt: 'Rest, trust your body, and prepare emotionally. Talk and sing to your baby — they will recognize your voice after birth.', xpReward: 30 },
  ];
  for (const m of newMilestones) {
    await prisma.milestoneExpectation.upsert({ where: { id: `seed_milestone_${m.stageKey}_${m.domain}_${m.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}` }, update: m, create: { id: `seed_milestone_${m.stageKey}_${m.domain}_${m.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}`, ...m } });
  }
  console.log(`Seeded ${newMilestones.length} new milestone expectations`);

